text:
&:before {
  border-radius: calc(var(--spectrum-calendar-day-width) + var(--spectrum-alias-focus-ring-gap));
  content: '';
  display: block;
  position: absolute;
  top: calc(50% - calc(var(--spectrum-calendar-day-width) / 2));
  left: calc(50% - calc(var(--spectrum-calendar-day-width) / 2));
  width: calc(var(--spectrum-calendar-day-width) + var(--spectrum-alias-focus-ring-gap) * 2);
  height: calc(var(--spectrum-calendar-day-height) + var(--spectrum-alias-focus-ring-gap) * 2);
  margin: 0;
  transform: translateX(0); /* Forces FF to render on the pixel grid */

  transition:
    box-shadow var(--spectrum-global-animation-duration-100) ease-out,
    margin var(--spectrum-global-animation-duration-100) ease-out;
}

%spectrum-ButtonWithFocusRing {
	&::after {
		content: "";

		position: absolute;
		inset-block-start: 0;
		inset-block-end: 0;
		inset-inline-start: 0;
		inset-inline-end: 0;

		display: block;

		margin: calc(-1 * var(--mod-button-focus-indicator-gap, var(--spectrum-focus-indicator-gap)));

		transition:
			opacity var(--mod-button-animation-duration, var(--mod-button-animation-duration, var(--spectrum-animation-duration-100))) ease-out,
			margin var(--mod-button-animation-duration, var(--mod-button-animation-duration, var(--spectrum-animation-duration-100))) ease-out;
	}

	&:focus-visible::after {
		margin: calc(-2 * var(--mod-focus-indicator-gap, var(--spectrum-focus-indicator-gap)));
	}
}

&::before {
	content: "";
	display: block;
	position: absolute;
	inset-inline-start: 50%;
	inset-block-start: 50%;

	transition:
		box-shadow var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-out,
		inline-size var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-out,
		block-size var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-out;

	inline-size: var(--mod-slider-handle-size, var(--spectrum-slider-handle-size));
	block-size: var(--mod-slider-handle-size, var(--spectrum-slider-handle-size));
	border-radius: 100%;

	transform: translate(-50%, -50%);

	.spectrum-Slider:dir(rtl) & {
		transform: translate(50%, -50%);
	}
}

&:where(:any-link, button, label) {
  @media (hover: hover) {
    &:where(:hover) {
      transition-duration: 40ms;
      box-shadow: var(--base-card-classic-hover-box-shadow-outer);
      &::after {
        box-shadow: var(--base-card-classic-hover-box-shadow-inner);
      }
    }
  }
  &:where([data-state='open']) {
    transition-duration: 40ms;
    box-shadow: var(--base-card-classic-hover-box-shadow-outer);
    &::after {
      box-shadow: var(--base-card-classic-hover-box-shadow-inner);
    }
  }
  &:where(:active:not([data-state='open'])) {
    transition-duration: 40ms;
    box-shadow: var(--base-card-classic-active-box-shadow-outer);
    &::after {
      box-shadow: var(--base-card-classic-active-box-shadow-inner);
    }
  }
}

&.withTransitions {
  transition:
    transform var(--transition-duration) ease-in,
    opacity var(--transition-duration) ease-in;

  &[data-ending-style] {
    transform: translate(-50%, -35%) scale(0.8, calc(pow(0.95, var(--nested-dialogs))))
      translateY(calc(-30px * var(--nested-dialogs)));
    opacity: 0;
  }

  &[data-open] {
    &[data-starting-style] {
      transform: translate(-50%, -35%) scale(0.8) translateY(0);
      opacity: 0;
    }

    transform: translate(-50%, -50%) scale(calc(pow(0.95, var(--nested-dialogs))))
      translateY(calc(-30px * var(--nested-dialogs)));
    transition:
      transform var(--transition-duration) ease-out,
      opacity var(--transition-duration) ease-out;
  }
}

&::before {
	transition:
		background var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-in-out,
		border var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-in-out,
		transform var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-in-out,
		box-shadow var(--mod-animation-duration-100, var(--spectrum-animation-duration-100)) ease-in-out;

	inline-size: var(--mod-switch-control-height, var(--spectrum-switch-control-height));
	block-size: var(--mod-switch-control-height, var(--spectrum-switch-control-height));

	inset-block-start: 0;
	inset-inline-start: 0;

	border-width: var(--mod-border-width-200, var(--spectrum-border-width-200));
	border-radius: calc(var(--mod-switch-control-height, var(--spectrum-switch-control-height)) / 2);
	border-style: solid;
}

&::before {
	content: "";
	position: absolute;

	box-sizing: border-box;

	block-size: calc(100% - var(--mod-tabs-top-to-text, var(--spectrum-tabs-top-to-text)));
	inline-size: calc(100% + var(--mod-tabs-focus-indicator-gap, var(--spectrum-tabs-focus-indicator-gap)) * 2);

	inset-block-start: calc(var(--mod-tabs-top-to-text, var(--spectrum-tabs-top-to-text)) / 2);
	inset-inline-start: calc(-1 * var(--mod-tabs-focus-indicator-gap, var(--spectrum-tabs-focus-indicator-gap)));
	inset-inline-end: calc(-1 * var(--mod-tabs-focus-indicator-gap, var(--spectrum-tabs-focus-indicator-gap)));

	border: var(--mod-tabs-focus-indicator-width, var(--spectrum-tabs-focus-indicator-width)) solid transparent;
	border-radius: var(--mod-tabs-focus-indicator-border-radius, var(--spectrum-tabs-focus-indicator-border-radius));

	pointer-events: none;
}

@breakpoints {
  .rt-BaseButton {
    &:where(.rt-r-size-1) {
      --base-button-classic-active-padding-top: 1px;
      --base-button-height: var(--space-5);
      border-radius: max(var(--radius-1), var(--radius-full));
    }
    &:where(.rt-r-size-2) {
      --base-button-classic-active-padding-top: 2px;
      --base-button-height: var(--space-6);
      border-radius: max(var(--radius-2), var(--radius-full));
    }
    &:where(.rt-r-size-3) {
      --base-button-classic-active-padding-top: 2px;
      --base-button-height: var(--space-7);
      border-radius: max(var(--radius-3), var(--radius-full));
    }
    &:where(.rt-r-size-4) {
      --base-button-classic-active-padding-top: 2px;
      --base-button-height: var(--space-8);
      border-radius: max(var(--radius-4), var(--radius-full));
    }
  }
}

@breakpoints {
  .rt-BaseTabList {
    &:where(.rt-r-size-1) {
      font-size: var(--font-size-1);
      line-height: var(--line-height-1);
      letter-spacing: var(--letter-spacing-1);
      --tab-height: var(--space-6);
      --tab-padding-x: var(--space-1);
      --tab-inner-padding-x: var(--space-1);
      --tab-inner-padding-y: calc(var(--space-1) * 0.5);
      --tab-inner-border-radius: var(--radius-1);
    }
    &:where(.rt-r-size-2) {
      font-size: var(--font-size-2);
      line-height: var(--line-height-2);
      letter-spacing: var(--letter-spacing-2);
      --tab-height: var(--space-7);
      --tab-padding-x: var(--space-2);
      --tab-inner-padding-x: var(--space-2);
      --tab-inner-padding-y: var(--space-1);
      --tab-inner-border-radius: var(--radius-2);
    }
  }
}

@breakpoints {
  .rt-Badge {
    &:where(.rt-r-size-1) {
      font-size: var(--font-size-1);
      line-height: var(--line-height-1);
      letter-spacing: var(--letter-spacing-1);
      padding: calc(var(--space-1) * 0.5) calc(var(--space-1) * 1.5);
      gap: calc(var(--space-1) * 1.5);
      border-radius: max(var(--radius-1), var(--radius-full));
    }
    &:where(.rt-r-size-2) {
      font-size: var(--font-size-1);
      line-height: var(--line-height-1);
      letter-spacing: var(--letter-spacing-1);
      padding: var(--space-1) var(--space-2);
      gap: calc(var(--space-1) * 1.5);
      border-radius: max(var(--radius-2), var(--radius-full));
    }
    &:where(.rt-r-size-3) {
      font-size: var(--font-size-2);
      line-height: var(--line-height-2);
      letter-spacing: var(--letter-spacing-2);
      padding: var(--space-1) calc(var(--space-2) * 1.25);
      gap: var(--space-2);
      border-radius: max(var(--radius-2), var(--radius-full));
    }
  }
}

&:where(.rt-r-size-1) {
  --select-content-padding: var(--space-1);
  --select-item-height: var(--space-5);
  --select-item-indicator-width: calc(var(--space-5) / 1.2);
  --select-separator-margin-right: var(--space-2);
  border-radius: var(--radius-3);

  & :where(.rt-SelectLabel) {
    font-size: var(--font-size-1);
    letter-spacing: var(--letter-spacing-1);
    line-height: var(--line-height-1);
  }
  & :where(.rt-SelectItem) {
    font-size: var(--font-size-1);
    line-height: var(--line-height-1);
    letter-spacing: var(--letter-spacing-1);
    border-radius: var(--radius-1);
  }
  & :where(.rt-SelectItemIndicatorIcon) {
    width: calc(8px * var(--scaling));
    height: calc(8px * var(--scaling));
  }
}
